#include <vector>
#include <algorithm>
#include <numeric>
#include <climits>

using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> rank;

    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        iota(parent.begin(), parent.end(), 0);
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    bool unite(int u, int v) {
        int pu = find(u);
        int pv = find(v);
        if (pu == pv) return false;
        if (rank[pu] > rank[pv]) {
            parent[pv] = pu;
        } else if (rank[pu] < rank[pv]) {
            parent[pu] = pv;
        } else {
            parent[pv] = pu;
            rank[pu]++;
        }
        return true;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;
    for (const auto& e : edges) {
        if (e[3] == 1) {
            must_edges.push_back(e);
        } else {
            optional_edges.push_back(e);
        }
    }

    DSU dsu(n);
    int components = n;

    // First, process all must edges
    for (const auto& e : must_edges) {
        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components == 1) {
        // All nodes are connected by must edges, find min strength among them
        long long min_strength = LLONG_MAX;
        for (const auto& e : must_edges) {
            min_strength = min(min_strength, e[2]);
        }
        return min_strength;
    }

    // Now, process optional edges without upgrades first to check connectivity
    vector<vector<long long>> sorted_optional = optional_edges;
    sort(sorted_optional.begin(), sorted_optional.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    DSU dsu_check = dsu;
    int temp_components = components;
    for (const auto& e : sorted_optional) {
        if (dsu_check.unite(e[0], e[1])) {
            temp_components--;
            if (temp_components == 1) break;
        }
    }
    if (temp_components != 1) {
        return -1;
    }

    // Binary search for the maximum possible min strength
    long long left = 1;
    long long right = 1e14;
    long long answer = -1;

    while (left <= right) {
        long long mid = (left + right) / 2;
        DSU dsu_mid(n);
        int comp_mid = n;

        // Process must edges first
        for (const auto& e : must_edges) {
            if (dsu_mid.unite(e[0], e[1])) {
                comp_mid--;
            }
        }

        // Process optional edges with possible upgrades
        int upgrades_used = 0;
        for (const auto& e : optional_edges) {
            long long strength = e[2];
            if (strength >= mid) {
                if (dsu_mid.unite(e[0], e[1])) {
                    comp_mid--;
                }
            } else if (strength * 2 >= mid && upgrades_used < k) {
                if (dsu_mid.unite(e[0], e[1])) {
                    comp_mid--;
                    upgrades_used++;
                }
            }
        }

        if (comp_mid == 1) {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}

